import { isCelError } from "./error.js";
import { toCel } from "./value.js";
export class ObjectActivation {
    constructor(data) {
        this.data = data;
    }
    resolve(name) {
        const value = this.data[name];
        if (value === undefined) {
            return undefined;
        }
        if (isCelError(value)) {
            return value;
        }
        return toCel(value);
    }
}
export class VarActivation {
    constructor(name, value, parent) {
        this.name = name;
        this.value = value;
        this.parent = parent;
    }
    resolve(name) {
        if (name === this.name) {
            return this.value;
        }
        return this.parent.resolve(name);
    }
}
export const EMPTY_ACTIVATION = {
    resolve() {
        return undefined;
    },
};
